import { getDb } from "@/lib/db";
import Header from "@/components/Header";

export default async function CatalogPage() {
    const supabase = await getDb();

    // Загружаем книги + связываем автора и жанр
    const { data: books = [], error } = await supabase
        .from("книги")
        .select(`
      id,
      название,
      isbn,
      год_издания,
      издательство,
      доступно_экземпляров,
      всего_экземпляров,
      авторы:книга_автор(автор:авторы(фио)),
      жанры:книга_жанр(жанр:жанр(название))
    `)
        .order("название", { ascending: true });

    if (error) console.error("Ошибка загрузки каталога:", error);

    // Приводим к удобному виду
    const formattedBooks = books.map(b => ({
        id: b.id,
        title: b.название,
        author: b.авторы?.[0]?.автор?.фио || "Неизвестно",
        year: b.год_издания || "—",
        genre: b.жанры?.[0]?.жанр?.название || "Без жанра",
        publisher: b.издательство,
        available: b.доступно_экземпляров,
        total: b.всего_экземпляров,
    }));

    return (
        <>
            <Header navLinks={[{label:"Каталог",href:"/catalog",id:"catalog"},{label:"Личный кабинет",href:"/dashboard",id:"dashboard"}]} />
            <div className="hero">
                <h1>Электронный <span>фонд</span></h1>
                <p>Каталог изданий — {formattedBooks.length} книг в вашей библиотеке</p>
            </div>
            <div className="container">
                {/* ... используй formattedBooks вместо моковых данных ... */}
                <div className="books-grid">
                    {formattedBooks.map(book => (
                        <div key={book.id} className="book-card">
                            <div className="book-cover">
                                <span className="book-initial">{book.title.charAt(0)}</span>
                            </div>
                            <div className="book-info">
                                <div className="book-title">{book.title}</div>
                                <div className="book-author">{book.author}</div>
                                <div className="book-meta">
                                    <span className="book-genre">{book.genre}</span>
                                    <span className="book-available">
                    <span className={`num ${book.available === 0 ? 'zero' : ''}`}>{book.available}</span> / {book.total}
                  </span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </>
    );
}